108	func (r *Reconciler) updateImage(deployment *appsv1.Deployment) error {
109		image := os.Getenv(istiocsrImageNameEnvVarName)
110		if image == "" {
111			return fmt.Errorf("%s environment variable with istiocsr image not set", istiocsrImageNameEnvVarName)
112		}
113		for i, container := range deployment.Spec.Template.Spec.Containers {
114			if container.Name == istiocsrContainerName {
115				deployment.Spec.Template.Spec.Containers[i].Image = image
116			}
117		}
118		return nil
119	}
